 1	import React, { ComponentClass, FC } from 'react';
 2	
 3	import { Divider, DrilldownMenu, MenuItem } from '@patternfly/react-core';
 4	
 5	type DrilldownMenuItemProps = {
 6	  Icon?: ComponentClass;
 7	  id: string;
 8	  label: string;
 9	};
10	
11	const DrilldownMenuItem: FC<DrilldownMenuItemProps> = ({ children, Icon, id, label }) => (
12	  <MenuItem
13	    drilldownMenu={
14	      <DrilldownMenu id={id}>
15	        <MenuItem direction="up" itemId={`${id}_breadcrumb`}>
16	          {label}
17	        </MenuItem>
18	        <Divider component="li" />
19	        {children}
20	      </DrilldownMenu>
21	    }
22	    direction="down"
23	    icon={Icon && <Icon />}
24	    itemId={id}
25	  >
26	    {label}
27	  </MenuItem>
28	);
29	
30	export default DrilldownMenuItem;

